fun main() {
    // Длина строки
    val language = "Hi"
    println(language.length) // 2

    // Конкатенация строк
    val str1 = "ab"
    val str2 = "cde"
    val result = str1 + str2 // "abcde"

    // Конкатенация с другими типами
    val stringPlusBoolean = "abc" + 10 + true
    println(stringPlusBoolean) // abc10true
}

fun main() {
    // Повторение строки
    print("Test".repeat(5)) // TestTestTestTestTest

    // Экранирование (escape-последовательности)
    println("'H' is the first letter of \"Hello world!\" string.")

    // Raw строка — с символами новой строки
    val some = """
        Какое-то хорошее предложение
        А потом еще одно
        И так далее.
    """.trimIndent()
}

fun main() {
    val city = "Moscow"
    val temp = "20"

    // ✅ Строковый шаблон — элегантно и читаемо
    println("The temperature in $city is $temp degrees Celsius.")

    // ❌ Конкатенация — громоздко и нечитаемо
    println("The temperature in " + city + " is " + temp + " degrees Celsius.")
}

fun main() {
    val city = "Moscow"
    println("The $city city has ${city.length} letters in the name")
    // The Moscow city has 6 letters in the name
}

fun main() {
    val example = "Good morning..."

    println(example.replace("morning", "bye"))
    // "Good bye..."

    println(example.replace('.', '!'))
    // "Good morning!!!"
}

fun main() {
    val sentence = "какой-то длинный текст"

    val wordsList: List<String> = sentence.split(" ")
    // ["какой-то", "длинный", "текст"]

    val mutableWordList = sentence.split(" ").toMutableList()
    // MutableList ["какой-то", "длинный", "текст"]
}

fun main() {
    val summer = "Теплое лето"
    for (i in 0 until summer.length) {
        print("${summer[i]} ")
    }
    // Т е п л о е   л е т о
}

fun main() {
    val charSequence: CharSequence = "Test message!"
    val str: String = charSequence.toString()
    println(str) // Test message!
}

fun main() {
    // Способ 1: через конструктор
    val sb = StringBuilder(100)    // с начальной ёмкостью 100
    val sb1 = StringBuilder("Test") // из строки

    // Способ 2: через функцию buildString
    val str = buildString {
        append("Скоро")
        append(' ')
        append("лето!")
    }
    println(str) // Скоро лето!
}

fun main() {
    // append — добавление в конец
    val str = buildString {
        append("Kotlin ") // добавляем String
        append(2.0)       // добавляем Double
    } // "Kotlin 2.0"

    // insert — вставка по индексу
    val str2 = buildString {
        append("Hello World")
        insert(5, ",")
    } // "Hello, World"

    // delete — удаление диапазона
    val str3 = buildString {
        append("That's impossible!")
        delete(7, 9)
    } // "That's possible!"
}

