fun main() {
    // val + mutable объект: содержимое можно менять
    val numbers = mutableListOf(1, 2, 3)
    numbers.add(4)  // ✅ Список mutable
    println(numbers)  // [1, 2, 3, 4]

    // var: можно присвоить новый объект
    var list = mutableListOf(1, 2)
    list = mutableListOf(3, 4)  // ✅ Переназначение
    println(list)  // [3, 4]
}

