fun main() {
    val a = 35   // 0..00100011
    val b = -35  // 1..11011101

    // Для положительного n: inv(n) = -(n+1)
    val inverseFirst = a.inv()  // -36

    // Для отрицательного -n: inv(-n) = n-1
    val inverseSecond = b.inv() // 34
}

fun main() {
    val x = 5
    val result = x and 1
    // 101 & 001 = 001 => result = 1
    // Значит x — нечётное (остаток 1)

    val y = 8
    val result2 = y and 1
    // 1000 & 0001 = 0000 => result2 = 0
    // Значит y — чётное (остаток 0)

    println(result)  // 1
    println(result2) // 0
}
